  ('dietitian-moex-05235', 'dietitian', 'dietitian-moex-110-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '下列灌食配方中蛋白質所占的熱量比例，何者之氮：非蛋白質熱量（nitrogen:non-proteincalorie） 之比值為1：150？', '["14.3%", "16.7%", "20.0%", "25.0%"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:40+00:00", "source_pdf_sha1": "fbf6ab0762fa", "answer_pdf_sha1": "f8f6714688dc", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "103", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
